import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.data.elasticsearch.client.RestClients;
import org.springframework.data.elasticsearch.core.ElasticsearchRestTemplate;
import org.springframework.data.elasticsearch.core.query.IndexQuery;
import org.springframework.data.elasticsearch.core.query.Query;
import org.springframework.data.elasticsearch.core.query.NativeSearchQueryBuilder;
import org.springframework.data.elasticsearch.core.query.NativeSearchQuery;
import org.springframework.data.elasticsearch.core.SearchHits;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.index.query.QueryBuilders;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.util.List;

@SpringBootApplication
public class ProductSearchApplication {
    public static void main(String[] args) {
        SpringApplication.run(ProductSearchApplication.class, args);
    }

    @Bean
    public RestHighLevelClient client(@Value("${elasticsearch.host}") String host) {
        return RestClients.create(ClientConfiguration.builder()
                .connectedTo(host)
                .build()).rest();
    }

    @Bean
    public ElasticsearchRestTemplate elasticsearchTemplate(RestHighLevelClient client) {
        return new ElasticsearchRestTemplate(client);
    }
}

@Service
public class ProductService {
    private final ElasticsearchRestTemplate elasticsearchTemplate;

    public ProductService(ElasticsearchRestTemplate elasticsearchTemplate) {
        this.elasticsearchTemplate = elasticsearchTemplate;
    }

    public void indexProduct(Product product) {
        IndexQuery indexQuery = new IndexQuery();
        indexQuery.setId(product.getId());
        indexQuery.setObject(product);
        elasticsearchTemplate.index(indexQuery);
    }

    public List<Product> searchProducts(String query) {
        NativeSearchQuery searchQuery = new NativeSearchQueryBuilder()
                .withQuery(QueryBuilders.multiMatchQuery(query, "name", "description"))
                .build();
        SearchHits<Product> searchHits = elasticsearchTemplate.search(searchQuery, Product.class);
        return searchHits.getSearchHits().stream()
                .map(hit -> hit.getContent())
                .toList();
    }
}

